 1 use crate::helpers::spawn_app;
 2 
 3 #[tokio::test]
 4 async fn get_forgot_password_returns_200_with_placeholder_page() {
 5     let app = spawn_app().await;
 6 
 7     let client = reqwest::Client::new();
 8     let response = client
 9         .get(format!("{}/forgot-password", &app.address))
10         .send()
11         .await
12         .expect("Failed to execute request");
13 
14     assert_eq!(response.status().as_u16(), 200);
15 
16     let content_type = response
17         .headers()
18         .get("content-type")
19         .expect("Missing content-type header")
20         .to_str()
21         .unwrap();
22     assert!(
23         content_type.contains("text/html"),
24         "Expected text/html, got {content_type}"
25     );
26 
27     let body = response.text().await.unwrap();
28 
29     // Page structure
30     assert!(body.contains("Forgot password"), "Missing page heading");
31     assert!(
32         body.contains("Forgot password -- Todo List"),
33         "Missing descriptive page title"
34     );
35 
36     // Placeholder message explaining feature is coming soon
37     assert!(
38         body.contains("coming soon"),
39         "Should explain that password reset is coming soon"
40     );
41 
42     // Link back to login
43     assert!(
44         body.contains("href=\"/login\""),
45         "Should have a link back to the login page"
46     );
47 }
